import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,r as s,t as c}from"./chunks/javadoc.By8MmAW1.js";const l=JSON.parse(`{"title":"Quellcode in IntelliJ IDEA generieren","description":"Ein Leitfaden zum Generieren von Minecraft Quellcode in IntelliJ IDEA.","frontmatter":{"title":"Quellcode in IntelliJ IDEA generieren","description":"Ein Leitfaden zum Generieren von Minecraft Quellcode in IntelliJ IDEA.","authors":["dicedpixels"],"prev":{"text":"Das Spiel in IntelliJ IDEA ausführen","link":"./launching-the-game"},"next":{"text":"Einen Mod in IntelliJ bauen","link":"./building-a-mod"},"files":[]},"headers":[],"relativePath":"de_de/develop/getting-started/intellij-idea/generating-sources.md","filePath":"translated/de_de/develop/getting-started/intellij-idea/generating-sources.md","lastUpdated":1772272927000}`);var u={name:`de_de/develop/getting-started/intellij-idea/generating-sources.md`};function d(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Quellcode in IntelliJ IDEA generieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Quellcode in IntelliJ IDEA generieren”">​</a></h1><p>Mit der Fabric-Toolchain kannst du auf den Quellcode von Minecraft zugreifen, indem du ihn lokal generierst, und du kannst IntelliJ IDEA verwenden, um bequem darin zu navigieren. Um den Quellcode zu generieren, musst du die <code>genSources</code>-Gradle-Aufgabe ausführen.</p><p>Dies kann in der Gradle-Leiste erfolgen, indem du die <code>genSources</code>-Aufgabe unter <strong>Tasks</strong> &gt; <strong><code>fabric</code></strong> ausführst: <img src="/assets/develop/getting-started/intellij/gradle-gensources.png" alt="genSources-Aufgabe in der Gradle-Ansicht" loading="lazy"></p><p>Oder du kannst auch den Befehl vom Terminal aus ausführen:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genSources</span></span></code></pre></div><p><img src="/assets/develop/getting-started/intellij/terminal-gensources.png" alt="genSources-Aufgabe im Terminal" loading="lazy"></p><h2 id="attaching-sources" tabindex="-1">Quellcode anhängen <a class="header-anchor" href="#attaching-sources" aria-label="Permalink to “Quellcode anhängen”">​</a></h2><p>IntelliJ erfordert einen zusätzlichen Schritt, um den generierten Quellcode an das Projekt anzuhängen.</p><p>Um dies zu tun, öffne eine Minecraft Klasse. Du kannst mit <kbd>Strg</kbd> + Klick zur Definition springen, wodurch die Klasse geöffnet wird, oder verwende &quot;Search everywhere&quot;, um eine Klasse zu öffnen.</p><p>Lasst uns <code>MinecraftServer.class</code> als Beispiel öffnen. Du solltest jetzt oben ein blaues Banner mit dem Link &quot;<strong>Quellen auswählen...</strong>&quot; sehen.</p><p><img src="/assets/develop/getting-started/intellij/choose-sources.png" alt="Quellcode auswählen" loading="lazy"></p><p>Klicke auf &quot;<strong>Choose Sources...</strong>&quot;, um einen Dialog zur Dateiauswahl zu öffnen. Dieser Dialog wird im Standard den richtigen Ort des generierten Quellcodes öffnen.</p><p>Wähle die Datei, die mit <strong><code>-sources</code></strong> endet und drücke <strong>Öffnen</strong> um die Auswahl zu bestätigen.</p><p><img src="/assets/develop/getting-started/intellij/choose-sources-dialog.png" alt="Quellcode Auswählen Dialog" loading="lazy"></p><p>Du solltest nun in der Lage sein, nach Referenzen zu suchen. Wenn du einen Mapping-Satz verwendest, der Javadocs enthält, wie <a href="https://parchmentmc.org/" target="_blank" rel="noreferrer">Parchment</a> (für Mojang Mappings) oder Yarn, solltest du nun auch Javadocs sehen.</p><p><img src="/assets/develop/getting-started/intellij/javadoc.png" alt="Javadoc Kommentare im Quellcode" loading="lazy"></p>`,16)]])}var f=r(u,[[`render`,d]]);export{l as __pageData,f as default};